python3 -c "
import sys
sys.path.insert(0, 'src')
from zh_copilot.replay.parser import parse_replay_bytes
from pathlib import Path

# Parse a few replays and print raw game_options S= field
files = sorted(Path('replays/dataset').glob('*.rep'))[:20]
for f in files:
    try:
        rep = parse_replay_bytes(f.read_bytes())
        opts = rep.header.game_options
        for token in opts.split(';'):
            if token.startswith('S='):
                slots = token[2:].split(':')
                for s in slots:
                    if s and s != 'X' and s != 'O' and not s.startswith('C'):
                        fields = s.split(',')
                        if len(fields) >= 6:
                            print(f'{f.name}: name={fields[0][1:]}, flags={fields[3]}, color={fields[4]}, template={fields[5]}')
    except:
        pass
" 2>/dev/null

