53	
54	}  // end ~NameKeyGenerator
55	
56	//------------------------------------------------------------------------------------------------- 
57	void NameKeyGenerator::init()
58	{
59		DEBUG_ASSERTCRASH(m_nextID == (UnsignedInt)NAMEKEY_INVALID, ("NameKeyGen already inited"));
60	
61		// start keys at the beginning again
62		freeSockets();
63		m_nextID = 1;
64	
65	}  // end init
66	
67	//------------------------------------------------------------------------------------------------- 
