69	{
70		freeSockets();
71		m_nextID = 1;
72	
73	}  // end reset
74	
75	//------------------------------------------------------------------------------------------------- 
76	void NameKeyGenerator::freeSockets()
77	{
78		for (Int i = 0; i < SOCKET_COUNT; ++i)
79		{
80			Bucket *next;
81			for (Bucket *b = m_sockets[i]; b; b = next)
82			{
83				next = b->m_nextInSocket;
84				b->deleteInstance();
85			}
86			m_sockets[i] = NULL;
87		}
88	
89	}  // end freeSockets
90	
91	/* ------------------------------------------------------------------------ */
92	inline UnsignedInt calcHashForString(const char* p)
93	{
94		UnsignedInt result = 0; 
95		Byte *pp = (Byte*)p;
96		while (*pp) 
97			result = (result << 5) + result + *pp++; 
98		return result;
99	}
100	
101	/* ------------------------------------------------------------------------ */
102	inline UnsignedInt calcHashForLowercaseString(const char* p)
103	{
104		UnsignedInt result = 0; 
105		Byte *pp = (Byte*)p;
106		while (*pp) 
107			result = (result << 5) + result + tolower(*pp++); 
108		return result;
109	}
