113	{
114		for (Int i = 0; i < SOCKET_COUNT; ++i)
115		{
116			for (Bucket *b = m_sockets[i]; b; b = b->m_nextInSocket)
117			{
118				if (key == b->m_key)
119					return b->m_nameString;
120			}
121		}
122		return AsciiString::TheEmptyString;
123	}
