            if slot.general in ('Random', 'Unknown', 'Observer'):
                _, general = infer_player_general(rep, slot.slot_number)
                resolved.append(general)
            else:
                resolved.append(slot.general)
        generals_matchups['_vs_'.join(sorted(resolved))] += 1
    except:
        pass

print('Top 1v1 matchups (with inference):')
for k, v in generals_matchups.most_common(15):
    print(f'  {v:4d}  {k}')
