125		seed[0] = ax;                   /* mov     seed,eax                     */
126		ax += 0x883126e9 - 0xf22d0e56;  /* add     eax,0883126e9h-0f22d0e56h    */
127		seed[1] = ax;                   /* mov     seed+4,eax                   */
128		ax += 0xc624dd2f - 0x883126e9;  /* add     eax,0c624dd2fh-0883126e9h    */
