# ---------------------------------------------------------------------------
# Per-player outcome inference from command stream
# ---------------------------------------------------------------------------

_INF = float("inf")
# Two players quitting within this many frames are considered a simultaneous
# quit (draw). 150 frames = 5 seconds at 30 fps.
_DRAW_FRAMES = 150


def infer_player_outcomes(replay: ReplayFile, slots: list) -> dict[int, float]:
    """Infer win/loss/draw outcome for each human slot without the game engine.

    Uses SELF_DESTRUCT commands (player quit/forfeit) and player_discons flags
    from the replay header. Works for all game modes: 1v1, 2v2, 3v3, FFA.

    Returns {slot_number: outcome} where outcome is 1.0=win, 0.0=loss, 0.5=draw/unknown.

    Algorithm:
      - Disconnected players → quit at frame 0 (loss).
      - SELF_DESTRUCT command → player forfeited at that frame.
      - In team games (team > 0): earliest-quitting team loses, other team wins.
      - In FFA / 1v1 (team == 0): last player standing (quit latest / never quit) wins.
      - Two players quitting within _DRAW_FRAMES of each other → draw (0.5).
    """
    # Collect first SELF_DESTRUCT frame per player_idx
    quit_frames_by_pidx: dict[int, int] = {}
    for cmd in replay.commands:
        if cmd.msg_type == MsgType.SELF_DESTRUCT and cmd.player_idx not in quit_frames_by_pidx:
            quit_frames_by_pidx[cmd.player_idx] = cmd.frame

    human_slots = [s for s in slots if s.is_human]
    if not human_slots:
        return {}

    # Per-slot quit frame (inf = never quit = still standing)
    slot_quit: dict[int, float] = {}
    for slot in human_slots:
        if replay.header.player_discons[slot.slot_number]:
            slot_quit[slot.slot_number] = 0.0  # disconnected = quit immediately
        elif slot.player_idx in quit_frames_by_pidx:
            slot_quit[slot.slot_number] = float(quit_frames_by_pidx[slot.player_idx])
        else:
            slot_quit[slot.slot_number] = _INF  # never quit

    is_team_game = any(s.team > 0 for s in human_slots)

    if is_team_game:
        # Group slot numbers by team id
        teams: dict[int, list[int]] = {}
        for slot in human_slots:
            teams.setdefault(slot.team, []).append(slot.slot_number)

        # Each team's "loss frame" = earliest quit among any member
        team_loss_frame: dict[int, float] = {
            team: min(slot_quit[s] for s in slot_nums)
            for team, slot_nums in teams.items()
        }

        # Team that lost first
        losing_team = min(team_loss_frame, key=team_loss_frame.__getitem__)
        losing_frame = team_loss_frame[losing_team]

        if losing_frame == _INF:
            # Nobody quit — ambiguous
            return {s.slot_number: 0.5 for s in human_slots}

        outcomes: dict[int, float] = {}
        for slot in human_slots:
            if slot.team == losing_team:
                outcomes[slot.slot_number] = 0.0
            else:
                # Win, unless their team also quit within draw threshold
                own_frame = team_loss_frame[slot.team]
                if own_frame - losing_frame <= _DRAW_FRAMES:
                    outcomes[slot.slot_number] = 0.5
                else:
                    outcomes[slot.slot_number] = 1.0
        return outcomes

    else:
        # 1v1 or FFA — winner is last player standing
        never_quit = [sn for sn, f in slot_quit.items() if f == _INF]

        if len(never_quit) == 1:
            return {s.slot_number: (1.0 if s.slot_number == never_quit[0] else 0.0) for s in human_slots}

        if len(never_quit) > 1:
            # Multiple players never quit — ambiguous
            return {s.slot_number: (0.5 if s.slot_number in never_quit else 0.0) for s in human_slots}

        # All players quit — winner is whoever quit last
        sorted_by_frame = sorted(slot_quit.items(), key=lambda x: x[1])
        last_sn, last_frame = sorted_by_frame[-1]
        prev_frame = sorted_by_frame[-2][1] if len(sorted_by_frame) > 1 else 0.0

        outcomes = {}
        for slot in human_slots:
            f = slot_quit[slot.slot_number]
            if f == last_frame:
                outcomes[slot.slot_number] = 0.5 if (last_frame - prev_frame) <= _DRAW_FRAMES else 1.0
            else:
                outcomes[slot.slot_number] = 0.0
        return outcomes

